SELECT /*+ INDEX_DESC(A PPS_ORDER_INFO_IDX1)*/ ORDER_NO, STATUS, F_GET_KT_CODE_NM('PPS_ORDER_INFO', 'STATUS', STATUS) STATUS_NM, TYPE, F_GET_KT_CODE_NM('PPS_ORDER_CODE', 'TYPE', TYPE) TYPE_NM, CD, F_GET_ORDER_CD_NM(TYPE, 'CD', CD) CD_NM, OP1, F_GET_ORDER_CD_NM(TYPE, 'OP1', OP1) OP1_NM, OP2, F_GET_ORDER_CD_NM(TYPE, 'OP2', OP2) OP2_NM, OP3, F_GET_ORDER_CD_NM(TYPE, 'OP3', OP3) OP3_NM, REQ_SALE_AMT, REQ_ORDER_CNT, REQ_REMARK, AGENT_ID, F_GET_AGENT_NM(AGENT_ID) AGENT_NM, TO_CHAR(ORDER_DT, 'YYYY-MM-DD HH24:MI:SS') ORDER_DT, DLV_METHOD, F_GET_KT_CODE_NM('PPS_ORDER_INFO', 'DLV_METHOD', DLV_METHOD) DLV_METHOD_NM, TO_CHAR(DLV_REQ_DT, 'YYYY-MM-DD') DLV_REQ_DT, DLV_ADDR, DLV_NAME, DLV_PHONE, DLV_NO, SEND_CNT, SEND_AMT, SEND_TOT_AMT, DECODE(SEND_FILE, '', 'N', 'Y') SEND_FILE_FLAG, TO_CHAR(SEND_DT, 'YYYY-MM-DD') SEND_DT, PAY_METHOD, F_GET_KT_CODE_NM('PPS_ORDER_INFO', 'PAY_METHOD', PAY_METHOD) PAY_METHOD_NM, PAY_FLAG, TO_CHAR(PAY_DT, 'YYYY-MM-DD') PAY_DT, TO_CHAR(END_DT, 'YYYY-MM-DD') END_DT FROM PPS_ORDER_INFO A WHERE ORDER_DT > TO_DATE('20170101', 'YYYYMMDD') AND AGENT_ID = #{agentId}
AND ORDER_DT >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND ORDER_DT < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND STATUS IN ('01', '05', '10')
AND STATUS IN ('10', '15', '19', '20')
AND STATUS IN ('20', '30')
AND STATUS = #{searchStatus}
AND TYPE = #{searchType}
AND DLV_METHOD = #{searchDlvMethod}
AND PAY_METHOD = #{searchPayMethod}
AND PAY_FLAG = #{searchPayFlag}
AND CD LIKE '%' || #{searchSValue} || '%'
AND CD IN (SELECT OP_CD FROM PPS_ORDER_CODE WHERE CODE_GUBUN = 'CD' AND OP_CD_NM LIKE '%' || #{searchSValue} || '%')
AND DLV_NAME LIKE '%' || #{searchSValue} || '%'
AND DLV_NO LIKE '%' || #{searchSValue} || '%'
AND DLV_PHONE LIKE '%' || #{searchSValue} || '%'
AND ORDER_NO LIKE '%' || #{searchSValue} || '%'

SELECT /*+ INDEX_DESC(A PPS_ORDER_INFO_IDX1)*/ NVL(ORDER_NO, '-') ORDER_NO, NVL(STATUS, '-') STATUS, NVL(F_GET_KT_CODE_NM('PPS_ORDER_INFO', 'STATUS', STATUS), '-') STATUS_NM, NVL(TYPE, '-') TYPE, NVL(F_GET_KT_CODE_NM('PPS_ORDER_CODE', 'TYPE', TYPE), '-') TYPE_NM, NVL(CD, '-') CD, NVL(F_GET_ORDER_CD_NM(TYPE, 'CD', CD), '-') CD_NM, NVL(OP1, '-') OP1, NVL(F_GET_ORDER_CD_NM(TYPE, 'OP1', OP1), '-') OP1_NM, NVL(OP2, '-') OP2, NVL(F_GET_ORDER_CD_NM(TYPE, 'OP2', OP2), '-') OP2_NM, NVL(OP3, '-') OP3, NVL(F_GET_ORDER_CD_NM(TYPE, 'OP3', OP3), '-') OP3_NM, NVL(REQ_SALE_AMT, 0) REQ_SALE_AMT, NVL(REQ_ORDER_CNT, 0) REQ_ORDER_CNT, NVL(REQ_REMARK, '-') REQ_REMARK, NVL(AGENT_ID, '-') AGENT_ID, NVL(F_GET_AGENT_NM(AGENT_ID), '-') AGENT_NM, NVL(F_GET_ADMIN_NM(ORDER_ADMIN), '-') ORDER_ADMIN_NM, NVL(TO_CHAR(ORDER_DT, 'YYYY-MM-DD HH24:MI:SS'), '-') ORDER_DT, NVL(DLV_METHOD, '-') DLV_METHOD, NVL(F_GET_KT_CODE_NM('PPS_ORDER_INFO', 'DLV_METHOD', DLV_METHOD), '-') DLV_METHOD_NM, NVL(TO_CHAR(DLV_REQ_DT, 'YYYY-MM-DD'), '-') DLV_REQ_DT, NVL(DLV_ADDR, '-') DLV_ADDR, NVL(DLV_NAME, '-') DLV_NAME, NVL(DLV_PHONE, '-') DLV_PHONE, NVL(DLV_NO, '-') DLV_NO, NVL(SEND_CNT, 0) SEND_CNT, NVL(SEND_AMT, 0) SEND_AMT, NVL(SEND_TOT_AMT, 0) SEND_TOT_AMT, NVL(DECODE(SEND_FILE, '', 'N', 'Y'), '-') SEND_FILE_FLAG, NVL(F_GET_ADMIN_NM(SEND_ADMIN), '-') SEND_ADMIN_NM, NVL(TO_CHAR(SEND_DT, 'YYYY-MM-DD'), '-') SEND_DT, NVL(PAY_METHOD, '-') PAY_METHOD, NVL(F_GET_KT_CODE_NM('PPS_ORDER_INFO', 'PAY_METHOD', PAY_METHOD), '-') PAY_METHOD_NM, NVL(PAY_FLAG, '-') PAY_FLAG, NVL(PAY_SEQ, 0) PAY_SEQ, NVL(F_GET_ADMIN_NM(PAY_ADMIN), '-') PAY_ADMIN_NM, NVL(TO_CHAR(PAY_DT, 'YYYY-MM-DD'), '-') PAY_DT, NVL(F_GET_ADMIN_NM(END_ADMIN), '-') END_ADMIN_NM, NVL(TO_CHAR(END_DT, 'YYYY-MM-DD'), '-') END_DT, NVL(REMARK, '-') REMARK FROM PPS_ORDER_INFO A WHERE ORDER_DT > TO_DATE('20170101', 'YYYYMMDD') AND AGENT_ID = #{agentId}
AND ORDER_DT >= TO_DATE(#{startDt}, 'YYYY-MM-DD')
AND ORDER_DT < TO_DATE(#{endDt}, 'YYYY-MM-DD')+1
AND STATUS IN ('01', '05', '10')
AND STATUS IN ('10', '15', '19', '20')
AND STATUS IN ('20', '30')
AND STATUS = #{searchStatus}
AND TYPE = #{searchType}
AND DLV_METHOD = #{searchDlvMethod}
AND PAY_METHOD = #{searchPayMethod}
AND PAY_FLAG = #{searchPayFlag}
AND CD LIKE '%' || #{searchSValue} || '%'
AND CD IN (SELECT OP_CD FROM PPS_ORDER_CODE WHERE CODE_GUBUN = 'CD' AND OP_CD_NM LIKE '%' || #{searchSValue} || '%')
AND DLV_NAME LIKE '%' || #{searchSValue} || '%'
AND DLV_NO LIKE '%' || #{searchSValue} || '%'
AND DLV_PHONE LIKE '%' || #{searchSValue} || '%'
AND ORDER_NO LIKE '%' || #{searchSValue} || '%'

SELECT TYPE, F_GET_KT_CODE_NM('PPS_ORDER_CODE', 'TYPE', TYPE) TYPE_NM, CD, F_GET_ORDER_CD_NM(TYPE, 'CD', CD) CD_NM, OP1, F_GET_ORDER_CD_NM(TYPE, 'OP1', OP1) OP1_NM, OP2, F_GET_ORDER_CD_NM(TYPE, 'OP2', OP2) OP2_NM, OP3, F_GET_ORDER_CD_NM(TYPE, 'OP3', OP3) OP3_NM, SALE_AMT, TOT_CNT, IN_CNT, OUT_CNT, CLOSE_CNT, SHOW_FLAG FROM PPS_ORDER_GOODS WHERE TYPE IS NOT NULL
