SELECT SEND_FILE,
	   SEND_ORG_FILE
FROM PPS_ORDER_INFO
WHERE ORDER_NO = #{orderNo}
	  AND AGENT_ID = #{agentId}
	  AND STATUS = '30'

SELECT CD AS value, DECODE(#{cdFlag}, 'Y', CD, CD_NM) AS text FROM PPS_ORDER_GOODS WHERE TYPE IS NOT NULL AND TYPE = #{searchType}
AND SHOW_FLAG = #{searchShowFlag}
ORDER BY CD ASC
